def add_cat50_temporal_sequence(df, team_games_lookup):
    """
    Cat50: TEMPORAL SEQUENCE ENCODING
    Encode last-10-game sequences as ordered features (not just rolling averages).
    Captures momentum direction, streak patterns, opponent-adjusted sequences.
    """
    features = {}
    for team_col, prefix in [('home_team', 'seq_home'), ('away_team', 'seq_away')]:
        for i in range(1, 11):  # 1=most recent, 10=oldest
            features[f'{prefix}_outcome_{i}'] = df.apply(
                lambda row: get_nth_recent_outcome(team_games_lookup, row[team_col], row['game_date'], i), axis=1
            )
            features[f'{prefix}_margin_{i}'] = df.apply(
                lambda row: get_nth_recent_margin(team_games_lookup, row[team_col], row['game_date'], i), axis=1
            )
            features[f'{prefix}_opp_elo_{i}'] = df.apply(
                lambda row: get_nth_recent_opp_elo(team_games_lookup, row[team_col], row['game_date'], i), axis=1
            )
            features[f'{prefix}_was_home_{i}'] = df.apply(
                lambda row: get_nth_recent_home_flag(team_games_lookup, row[team_col], row['game_date'], i), axis=1
            )
    return pd.DataFrame(features)
